frame_eqs:
zoom = 1.0878;
// elastic thread code

xx1 = xx1*0.67 + (bass)*0.011;
xx2 = xx2*0.99 + (treb)*0.008;
yy1 = yy1*1.043 + (treb+bass)*0.00885;
x1 = 0.42 + (xx1-xx2)*2;
y1 = 0.48 + yy1*1.2;
dt = 0.03/fps;
vx2 = vx2*(1-2*dt) + dt*((x1+x3-2*x2)*10);
vy2 = vy2*(1-2*dt) + dt*((y1+y3-2*y2)*10-0.5);
vx3 = vx3*(1-2*dt) + dt*((x2+x4-2*x3)*10);
vy3 = vy3*(1-2*dt) + dt*((y2+y4-2*y3)*10-0.5);
vx4 = vx4*(1-2*dt) + dt*((x3-x4)*10);
vy4 = vy4*(1-2*dt) + dt*((y3-y4)*10-0.5);
x2 = x2 + vx2; y2 = y2 + vy2;
x3 = x3 + vx3; y3 = y3 + vy3;
x4 = x4 + vx4; y4 = y4 + vy4;
vx2 = if(above(x2,0),vx2,abs(vx2)*0.5);
vx2 = if(below(x2,1),vx2,-abs(vx2)*0.5);
vx3 = if(above(x3,0),vx3,abs(vx3)*0.5);
vx3 = if(below(x3,1),vx3,-abs(vx3)*0.61);
vx4 = if(above(x4,0),vx4,abs(vx4)*0.5);
vx4 = if(below(x4,1),vx4,-abs(vx4)*0.5);
vy2 = if(above(y2,0),vy2,abs(vy2)*0.5);
vy2 = if(below(y2,1),vy2,-abs(vy2)*0.48);
vy3 = if(above(y3,0),vy3,abs(vy3)*0.5);
vy3 = if(below(y3,1),vy3,-abs(vy3)*0.5);
vy4 = if(above(y4,0),vy4,abs(vy4)*0.5);
vy4 = if(below(y4,1),vy4,-abs(vy4)*0.5);
q1 = x1;q2 = x2;q3 = x3;q4 = x4;
q5 = y1;q6 = y2;q7 = y3;q8 = y4;
q9 = 1/aspectx;
q10 = 1/aspecty;
q11 = aspectx;
q12 = aspecty;
q13 = sqrt(vx4*vx4 + vy4*vy4);
q14 = atan2(vx4,vy4);
q15 = sin(q14);
q16 = cos(q14);

wave_0_per_point:
sp = sample*6.28*8*8*4;
vol = (bass_att + mid_att + treb_att)*0.419;
vol = 0.24 + 0.36*(value1 + value2);
vol = .2;

mod = if(below(mid_att,1.8),mid_att+.2,2);

ox = 0.5*sin(sp)*sin(sample*3.14)*vol;
oy = (sample - 0)*mod;
oz = 0.5*cos(sp)*sin(sample*3.14)*vol;

xang = time*0.5846;
axang = 0;
yang = time*-1.351;
ayang = 0;
zang = time*-0.5133;
azang = 0;
fov = 0.52 + 0.21*sin(time);
fov = .5;

mx = ox*cos(zang) - oy*sin(zang);
my = ox*sin(zang) + oy*cos(zang);
ox = mx;
oy = my;
mx = ox*cos(yang) + oz*sin(yang);
mz = - ox*sin(yang) + oz*cos(yang);
ox = mx;
oz = mz;
my = oy*cos(xang) - oz*sin(xang);
mz = oy*sin(xang) + oz*cos(xang);
oy = my;
oz = mz;

oz = abs(oz) - 2;
x = ox*fov/oz + 0.42;
x = (x-.5)*0.75 + 0.5;
y = oy*fov/oz + 0.5;

r = 1 + sin(sp);
b = 0.637 + 0.637*sin(sample*1.617);
g = 0.5 + 0.5*cos(sample*1.57);
a = 0.5 + (oz + 2)*0.25;

